using System;
using System.Net;
using System.Net.Http;
using System.Windows.Forms;
class ImageLoader
{
    void LoadImage(PictureBox pictureBox, string url)
    {
        // .NET 9: PictureBox now raises HttpRequestException/TaskCanceledException
        // instead of WebException when loading images from URLs fails.
        try { pictureBox.Load(url); }
        catch (HttpRequestException ex) { Console.WriteLine("Failed: " + ex.Message); }
        catch (TaskCanceledException ex) { Console.WriteLine("Timeout: " + ex.Message); }
    }
}

